public int totalHammingDistance(int[] nums) {
    int totalDistance = 0, n = nums.length;

    for (int i = 0; i < 32; ++i) {
        int bitCount = 0;
        for (int num : nums) {
            bitCount += (num >> i) & 1;
        }
        totalDistance += bitCount * (n - bitCount);
    }

    return totalDistance;
}
```

